module top_module(
		input [1:0]Rx,
		input clk, 
		input reset,
		input [1:0] identidad, 
		output reg bandera
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk, posedge reset or posedge dbg_halt)
	 	begin
			if (reset)
				bandera<=0;
			else 
				if(identidad == Rx)
					bandera<=1;
				else
					bandera<=0;
		end


endmodule
